mapper.insert:
/* com.matjzing.mapper.FrontCommentMapper.insertFrontComment */
INSERT INTO COMMENT (
	  CANDIDATE_SEQ /*후보자(대상) 일련번호*/
	, MEMBER_SEQ /*회원 시퀀스*/
	, CONTENT /*댓글 내용*/
	, USE_YN /*사용 여부*/
	, REGISTER_SEQ /*등록자 일련번호*/
	, REGISTER_IP /*등록자 IP*/
	, REGISTRATION_DT /*등록 일시*/
	, UPDATER_SEQ /*수정자 일련번호*/
	, UPDATER_IP /*수정자 IP*/
	, UPDATE_DT /*수정 일시*/
) VALUES (
	  #{candidateSeq}
	, COALESCE(#{memberSeq}, #{registerSeq})
	, #{content}
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)
